
  CREATE TABLE "DIRKSPZM32"."LVS_LTE_CFG" 
   (	"SID" VARCHAR2(2 CHAR) NOT NULL ENABLE, 
	"FIRMA_NR" NUMBER(2,0) NOT NULL ENABLE, 
	"LTE_NAME" VARCHAR2(22 CHAR) NOT NULL ENABLE, 
	"LTE_TEXT" VARCHAR2(60 CHAR), 
	"LTE_VOL_HOEHE" NUMBER(*,3), 
	"LTE_VOL_BREITE" NUMBER(*,3), 
	"LTE_VOL_TIEFE" NUMBER(*,3), 
	"LTE_GEW_KG" NUMBER(*,6), 
	"LTE_ID_GUELTIG_TAGE" NUMBER(*,5), 
	"VERWALTET_VON" VARCHAR2(20 CHAR) DEFAULT 'ISI' NOT NULL ENABLE, 
	"HOST_REF_ID" VARCHAR2(10 CHAR), 
	"STAPELFAKTOR" NUMBER(*,5) DEFAULT 99 NOT NULL ENABLE, 
	"FLAECHEN_STELLPLATZ_ERF" VARCHAR2(1 CHAR) DEFAULT 'F' NOT NULL ENABLE, 
	"LTE_VOL_HOEHE_FEST" VARCHAR2(1 CHAR) DEFAULT 'F' NOT NULL ENABLE, 
	"BASIS_LTE_NAME" VARCHAR2(15 CHAR), 
	"VIRTUELL" VARCHAR2(1 CHAR) DEFAULT 'F', 
	"TRANSPORT_EINHEIT" VARCHAR2(10 CHAR) DEFAULT 'LTE' NOT NULL ENABLE, 
	"GABEL_HOEHEN_OFFSET" NUMBER(*,3) DEFAULT 0 NOT NULL ENABLE
   ) ;
ALTER TABLE "DIRKSPZM32"."LVS_LTE_CFG" ADD CONSTRAINT "LVS_LTE_CFG_BASIS_LTE_NAME" CHECK (BASIS_LTE_NAME in ('Euro', 'Indu', 'DueDo', 'LHM')) ENABLE;
ALTER TABLE "DIRKSPZM32"."LVS_LTE_CFG" ADD CONSTRAINT "LVS_LTE_CFG_VIRTUELL" CHECK (VIRTUELL in ('F', 'T',  'L')) ENABLE;
ALTER TABLE "DIRKSPZM32"."LVS_LTE_CFG" ADD CONSTRAINT "LVS_LTE_TRANSPORT_EINHEIT" CHECK (TRANSPORT_EINHEIT in ('LTE', 'LHM', 'LTE_LTE', 'LTE_LHM')) ENABLE;
ALTER TABLE "DIRKSPZM32"."LVS_LTE_CFG" ADD CONSTRAINT "PK_LVS_LTE_CFG" PRIMARY KEY ("LTE_NAME", "SID")
  USING INDEX  ENABLE;


